INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9939f9c8-dfe2-4d9c-b9e1-c12c60e7792a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Solidity Fundamentals: Understanding State Variables and Visibility$escape$,
  $escape$Solidity state variables can be declared as public, internal, external, or private. Public state variables automatically generate getter functions, while internal and external variables are restricted to the contract or its derived contracts. Private variables are restricted to the contract itself. State variables can also be declared as immutable or constant to restrict their modification. The `view` and `pure` modifiers can be used to restrict the functionality of functions, with `view` allowing read access to state variables and `pure` disallowing any state variable access.$escape$,
  $escape$contract Example { uint public publicVar; uint internal internalVar; function getPublicVar() public view returns (uint) { return publicVar; } }$escape$,
  $escape$solidity$escape$,
